#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cmath>
#include <unordered_map>

// Problem 016 — RoPE inverse-frequency initialization.
//
//   inv_freq[i] = 1 / rope_theta^(2*i / head_dim)
//               = exp2(i * c),   c = -log2(rope_theta) / 64
//
// This op is pure launch/latency-bound: a 256-byte, write-only, 64-element
// output.  The prior champion (single-kernel launch, in-kernel exp2f) runs at
// ~1.84 us while the SOL floor is ~0.40 us — the ~1.44 us excess is kernel
// launch + dispatch overhead, not compute.
//
// Lever pulled here: CUDA-graph capture of the raw kernel, cached per
// rope_theta value.  On first sight of a theta we capture the single-kernel
// launch into a CUDA graph; on repeat calls we replay the graph (lower
// overhead than a fresh launch) and clone the static output buffer.  The
// host-side log2 fold is preserved from the champion.  __exp2f is used
// explicitly to guarantee the fast SFU intrinsic regardless of whether
// --use_fast_math is set.

constexpr int HEAD_DIM = 128;
constexpr int N = HEAD_DIM / 2;  // 64

__global__ void __launch_bounds__(N)
rope_inv_freq_kernel(float* __restrict__ out, float c)
{
    const int i = threadIdx.x;
    if (i < N) {
        out[i] = __exp2f(static_cast<float>(i) * c);
    }
}

// Per-theta graph cache: rope_theta -> executable graph.
static std::unordered_map<float, cudaGraphExec_t> graph_cache;
static float* static_out = nullptr;
static cudaStream_t stream = nullptr;

torch::Tensor run(float rope_theta)
{
    // Lazy-init: create stream and static output buffer once.
    if (!stream) {
        cudaStreamCreate(&stream);
        cudaMalloc(&static_out, N * sizeof(float));
    }

    // Compute scale factor on host (double → correctly-rounded fp32).
    const double L = std::log2(static_cast<double>(rope_theta));
    const float  c = static_cast<float>(-L / static_cast<double>(N));

    auto it = graph_cache.find(rope_theta);
    if (it == graph_cache.end()) {
        // First call for this theta: capture the kernel into a CUDA graph.
        cudaStreamBeginCapture(stream, cudaStreamCaptureModeGlobal);
        rope_inv_freq_kernel<<<1, N, 0, stream>>>(static_out, c);
        cudaGraph_t graph;
        cudaStreamEndCapture(stream, &graph);

        cudaGraphExec_t exec;
        cudaGraphInstantiate(&exec, graph, NULL, NULL, 0);
        cudaGraphDestroy(graph);

        it = graph_cache.emplace(rope_theta, exec).first;
    }

    // Replay the cached graph (writes to static_out).
    cudaGraphLaunch(it->second, stream);

    // Clone static buffer to a fresh output tensor on the same stream
    // (ordered after the graph completes).
    auto out = torch::empty(
        {N},
        torch::TensorOptions()
            .dtype(torch::kFloat32)
            .device(torch::kCUDA));
    cudaMemcpyAsync(out.data_ptr<float>(), static_out,
                    N * sizeof(float), cudaMemcpyDeviceToDevice, stream);
    cudaStreamSynchronize(stream);

    return out;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m)
{
    m.def("run", &run, "RoPE inverse frequency (float scalar -> (64,) fp32)");
}

